B.afU=new A.di("Otomatik botlar veya scraper kullanmak",null)
B.afX=new A.di("Uygulamay\u0131 s\u0131nav s\u0131ras\u0131nda kopya \xe7ekmek i\xe7in kullanmak",null)
B.afR=new A.di("Yasalara ayk\u0131r\u0131 i\xe7erik g\xf6ndermek",null)
B.aia=new A.h2("Fikri M\xfclkiyet",null)
B.ahE=new A.fL("Uygulama ve i\xe7eri\u011fi Evlumba Software'a aittir. AI taraf\u0131ndan \xfcretilen \xe7\xf6z\xfcmler e\u011fitim ama\xe7l\u0131d\u0131r ve do\u011frulu\u011fu garanti edilmez.",null)
